import tkinter as tk
from tkinter import simpledialog, messagebox
from PIL import Image, ImageTk, ImageDraw
import os
import base64
import io

# Размеры карточек
CARD_WIDTH = 220
CARD_HEIGHT = 180
IMG_WIDTH = 120
IMG_HEIGHT = 120

CONFIG_FILE = "maps.txt"

# Стандартный маппул
DEFAULT_MAPS = [
    "de_dust2",
    "de_mirage",
    "de_inferno",
    "de_vertigo",
    "de_train",
    "de_anubis",
    "de_ancient",
    "de_ancient_night",
    "de_overpass",
    "de_nuke"
]

EMBEDDED_IMAGES = {
    "de_dust2": """

    """,
    "de_mirage": """

    """,
    "de_inferno": """

    """,
    "de_vertigo": """

    """,
    "de_train": """

    """,
    "de_anubis": """

    """,
    "de_ancient": """

    """,
    "de_ancient_night": """

    """,
    "de_overpass": """

    """,
    "de_nuke": """

    """,

}


class MapCard:
    def __init__(self, master, map_name, app, image_path=None):
        self.master = master
        self.map_name = map_name
        self.app = app
        self.is_crossed = False
        self.is_selected = False

        self.canvas = tk.Canvas(
            master,
            width=CARD_WIDTH,
            height=CARD_HEIGHT,
            bg="#f0f0f0",
            highlightthickness=2,
            highlightbackground="#f0f0f0"
        )

        self.photo = self.load_image(image_path or f"{map_name}.jpg")

        self.img_id = self.canvas.create_image(
            CARD_WIDTH // 2, 10,
            anchor=tk.N,
            image=self.photo
        )

        self.text_id = self.canvas.create_text(
            CARD_WIDTH // 2,
            IMG_HEIGHT + 20,
            text=map_name,
            font=("Arial", 12, "bold"),
            fill="black"
        )

        self.line_id = self.canvas.create_line(
            0, 0, 1, 1,
            fill="red",
            width=4,
            state=tk.HIDDEN
        )

        self.canvas.bind("<Button-1>", self.toggle_cross)
        self.canvas.bind("<Button-3>", self.select_card)

    def load_image(self, path):
        """Пытается загрузить изображение: сначала из файла, затем из встроенных base64, иначе заглушка."""
        # 1. Пробуем загрузить из внешнего файла (позволяет переопределять картинки)
        try:
            img = Image.open(path)
            img = img.resize((IMG_WIDTH, IMG_HEIGHT), Image.Resampling.LANCZOS)
            return ImageTk.PhotoImage(img)
        except Exception:
            pass

        # 2. Пробуем взять из встроенного словаря по имени карты (без расширения)
        base_name = os.path.splitext(os.path.basename(path))[0]
        if base_name in EMBEDDED_IMAGES:
            try:
                img_data = base64.b64decode(EMBEDDED_IMAGES[base_name])
                img = Image.open(io.BytesIO(img_data))
                img = img.resize((IMG_WIDTH, IMG_HEIGHT), Image.Resampling.LANCZOS)
                return ImageTk.PhotoImage(img)
            except Exception:
                pass

        # 3. Если ничего не вышло – серая заглушка с названием
        img = Image.new("RGB", (IMG_WIDTH, IMG_HEIGHT), color="#cccccc")
        draw = ImageDraw.Draw(img)
        bbox = draw.textbbox((0, 0), self.map_name)
        text_width = bbox[2] - bbox[0]
        text_height = bbox[3] - bbox[1]
        position = ((IMG_WIDTH - text_width) // 2, (IMG_HEIGHT - text_height) // 2)
        draw.text(position, self.map_name, fill="black")
        return ImageTk.PhotoImage(img)

    def toggle_cross(self, event=None):
        self.is_crossed = not self.is_crossed
        if self.is_crossed:
            self.canvas.coords(self.line_id, 10, 10, CARD_WIDTH-10, CARD_HEIGHT-10)
            self.canvas.itemconfig(self.line_id, state=tk.NORMAL)
            self.canvas.itemconfig(self.text_id, fill="gray")
        else:
            self.canvas.itemconfig(self.line_id, state=tk.HIDDEN)
            self.canvas.itemconfig(self.text_id, fill="black")

    def select_card(self, event=None):
        self.app.deselect_all()
        self.is_selected = True
        self.canvas.config(highlightbackground="blue", highlightcolor="blue")
        self.app.selected_card = self


class MapPickerApp:
    def __init__(self, root):
        self.root = root
        self.root.title("CS2 Map Picker")
        self.root.resizable(True, True)

        control_frame = tk.Frame(root, bg="#e0e0e0")
        control_frame.pack(fill=tk.X, padx=10, pady=5)

        tk.Button(control_frame, text="Обновить из maps.txt", command=self.load_maps).pack(side=tk.LEFT, padx=5)
        tk.Button(control_frame, text="Сбросить стандартный пул", command=self.reset_default).pack(side=tk.LEFT, padx=5)
        tk.Button(control_frame, text="Добавить карту", command=self.add_map).pack(side=tk.LEFT, padx=5)
        tk.Button(control_frame, text="Удалить выделенную", command=self.delete_selected).pack(side=tk.LEFT, padx=5)
        tk.Button(control_frame, text="Сбросить зачёркивания", command=self.reset_crosses).pack(side=tk.LEFT, padx=5)

        self.cards_frame = tk.Frame(root, bg="#e0e0e0")
        self.cards_frame.pack(padx=10, pady=10, fill=tk.BOTH, expand=True)

        self.cards = []
        self.selected_card = None

        self.load_maps()

    def load_maps(self):
        if not os.path.exists(CONFIG_FILE):
            self.save_default_maps()

        with open(CONFIG_FILE, "r", encoding="utf-8") as f:
            map_names = [line.strip() for line in f if line.strip()]

        for widget in self.cards_frame.winfo_children():
            widget.destroy()
        self.cards.clear()
        self.selected_card = None

        for i, name in enumerate(map_names):
            card = MapCard(self.cards_frame, name, self)
            row, col = divmod(i, 5)
            card.canvas.grid(row=row, column=col, padx=5, pady=5)
            self.cards.append(card)

    def save_default_maps(self):
        with open(CONFIG_FILE, "w", encoding="utf-8") as f:
            f.write("\n".join(DEFAULT_MAPS))

    def reset_default(self):
        self.save_default_maps()
        self.load_maps()

    def add_map(self):
        name = simpledialog.askstring("Добавить карту", "Введите название карты (например de_cache):")
        if not name:
            return
        with open(CONFIG_FILE, "a", encoding="utf-8") as f:
            f.write(f"\n{name}")
        self.load_maps()
        messagebox.showinfo("Готово", f"Карта '{name}' добавлена.\n"
                                       f"Чтобы отобразить её изображение, положите файл '{name}.jpg' в папку с программой.")

    def delete_selected(self):
        if not self.selected_card:
            messagebox.showwarning("Нет выделения", "Выделите карту правой кнопкой мыши.")
            return
        name = self.selected_card.map_name
        with open(CONFIG_FILE, "r", encoding="utf-8") as f:
            lines = f.readlines()
        with open(CONFIG_FILE, "w", encoding="utf-8") as f:
            for line in lines:
                if line.strip() != name:
                    f.write(line)
        self.load_maps()
        self.selected_card = None

    def deselect_all(self):
        for card in self.cards:
            card.is_selected = False
            card.canvas.config(highlightbackground="#f0f0f0")
        self.selected_card = None

    def reset_crosses(self):
        for card in self.cards:
            if card.is_crossed:
                card.is_crossed = False
                card.canvas.itemconfig(card.line_id, state=tk.HIDDEN)
                card.canvas.itemconfig(card.text_id, fill="black")


if __name__ == "__main__":
    root = tk.Tk()
    app = MapPickerApp(root)
    root.mainloop()